using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string Text { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences to include in the summary.
    /// Defaults to 3.
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalWordCount { get; set; }
    public int SummaryWordCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    string Summarize(string text, int maxSentences);
}

/// <summary>
/// Extractive summarizer that scores sentences by word frequency and
/// returns the top-ranked sentences in their original order.
/// </summary>
public partial class DocumentSummarizer : IDocumentSummarizer
{
    private static readonly char[] s_wordSeparators = [' ', '\t', '\n', '\r'];

    public string Summarize(string text, int maxSentences)
    {
        var sentences = SplitSentences(text);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scored = ScoreSentences(sentences, wordFrequencies);

        var topIndices = scored
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .Select(s => s.Index)
            .Order()                     // preserve original order
            .ToList();

        return string.Join(" ", topIndices.Select(i => sentences[i]));
    }

    private static List<string> SplitSentences(string text)
    {
        // Split on sentence-ending punctuation followed by whitespace or end-of-string.
        var raw = SentenceRegex().Split(text);
        return raw
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in GetWords(sentence))
            {
                if (word.Length < 3) continue; // skip very short words
                freq[word] = freq.GetValueOrDefault(word) + 1;
            }
        }
        return freq;
    }

    private static List<(int Index, double Score)> ScoreSentences(
        List<string> sentences,
        Dictionary<string, int> wordFrequencies)
    {
        var scored = new List<(int Index, double Score)>(sentences.Count);
        for (int i = 0; i < sentences.Count; i++)
        {
            var words = GetWords(sentences[i]);
            if (words.Length == 0)
            {
                scored.Add((i, 0));
                continue;
            }

            double score = words
                .Where(w => w.Length >= 3)
                .Sum(w => wordFrequencies.GetValueOrDefault(w));

            // Normalise by word count to avoid bias toward long sentences.
            scored.Add((i, score / words.Length));
        }
        return scored;
    }

    private static string[] GetWords(string sentence) =>
        sentence.Split(s_wordSeparators, StringSplitOptions.RemoveEmptyEntries);

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController(IDocumentSummarizer summarizer) : ControllerBase
{
    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        if (!ModelState.IsValid)
            return ValidationProblem();

        var summary = summarizer.Summarize(request.Text, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalWordCount = WordCount(request.Text),
            SummaryWordCount = WordCount(summary)
        });
    }

    private static int WordCount(string text) =>
        text.Split((char[]?)null, StringSplitOptions.RemoveEmptyEntries).Length;
}

